style_git_commit = r"""
    draw=black!60,
    fill=green!40!lightgray,
    minimum width=2cm,
    minimum height=1cm,
    rounded rectangle,
    line width=2pt
"""


style_git_pointer = r"""
    draw=black!60,
    -Triangle,
    line width=2pt
"""


%%tikz -pt -e -tp xelatex -p "$preamble" -r -d 300 -S fig_log_01
\begin{tikzpicture}
\begin{scope}[
    every node/.style={(* style_git_commit *)},
    every path/.style={(* style_git_pointer *)}
]
\node (c1) at (0,0) {c1};
\node (c2) at (3,0) {c2}; \path (c2) edge (c1);
\node (c3) at (6,0) {c3}; \path (c3) edge (c2);
\end{scope}
\node at (0,2) {file1.txt 추가};
\node at (3,2) {file1.txt 변경};
\node at (3,1.5) {file2.txt 추가};
\node at (6,2) {(file1.txt 삭제)};
\node at (6,1) {file3.txt 추가};
\end{tikzpicture}

\documentclass{standalone}
\usepackage{kotex}
\usepackage{tikz}
\usetikzlibrary{shapes.misc}
\usetikzlibrary{arrows.meta}
\setmainfont{Noto Sans KR}
\begin{document}
    \begin{tikzpicture}
    \begin{scope}[
        every node/.style={
        draw=black!60,
        fill=green!40!lightgray,
        minimum width=2cm,
        minimum height=1cm,
        rounded rectangle,
        line width=2pt
    },
        every path/.style={
        draw=black!60,
        -Triangle,
        line width=2pt
    }
    ]
    \node (c1) at (0,0) {c1};
    \node (c2) at (3,0) {c2}; \path (c2) edge (c1);
    \node (c3) at (6,0) {c3}; \path (c3) edge (c2);
    \end{scope}
    \node at (0,2) {file1.txt 추가};
    \node at (3,2) {file1.txt 변경};
    \node at (3,1.5) {file2.txt 추가};
    \node at (6,2) {(file1.txt 삭제)};
    \node at (6,1) {file3.txt 추가};
    \end{tikzpicture}
\end{document}

같은 브랜치의 로컬 버전과 원격 버전에 서로 다른 커밋이 들어가서 달라진 상태
원격 브랜치에 다른 사람이 커밋 또는 머지를 했는데 이를 로컬에 반영하지 않은 상태에서 커밋을 해 버려서 발생






